  ('generalpolice-f3743df6-moex-00123', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '依民法之規定，下列敘述何者正確？', '["如民眾出示其為不識字之證明者，其指印或十字，與其親自簽名之效力相同", "關於一定之數量，同時以兩種文字與數字號碼以上表示者，兩者如不符合時，如法院不能決定何者 為當事人之原意，應以當事人之母國文字為準", "民眾於銀行、信用合作社或農漁會進行交易時，如用印鑑章代簽名者，其用印鑑章之效力大於本人 親自簽名", "依法律之規定，有使用文字之必要者，得不由本人自寫，但必須親自簽名"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00124', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '下列何者非信賴保護原則之要件？', '["信賴基礎", "信賴行為", "值得保護之信賴", "無不當聯結"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00125', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '法律案經立法院移送總統公布者，曾否踐行其議事應遵循之程序，除明顯牴觸憲法者外，行政、司法 或其他國家機關均應予以尊重。學理上稱為何種原則？', '["國會自律原則", "法律保留原則", "法不溯及既往原則", "機關忠誠原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00126', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '關於命令的效力，下列敘述何者正確？', '["總統依憲法增修條文規定所發布之緊急命令，於必要時得暫時停止部分憲法條文之適用", "行政機關獲法律授權制定命令時，如知母法有缺漏不備之處，得逾越授權意旨逕行補充", "行政命令縱使獲有法律授權而制定者，依憲法規定依舊不得作為限制人民基本權利之依據", "普通法院法官於審查個案，認所應適用之行政命令有牴觸母法意旨時，得逕行拒絕適用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00127', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '文義解釋是一項重要的法律解釋方法，學者多認為，法官解釋法律應避免任意超過法律文義進行適 用，以避免造成法官任意扭曲法律之結果。關於文義解釋的說明，下列何者最為適當？', '["對於刑法的解釋只能依據文義解釋，避免法官類推適用刑法，違反罪刑法定主義", "基於讓人民理解，文義解釋應該只採取日常生活所使用的文義，法律不能自行定義文義", "文義解釋可能會產生多種不同的結果，此時須運用其他的解釋方法來協助正確解釋法律", "為確保能以文義解釋來正確解釋法律，立法時應確保法律都只有單一意義，不可使用不確定法律 概念"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
